package problems;

public class maximumSubarray {

    public static void main(String[] args) {
        int[] nums = {-2, 1, -3, 4, -1, 2, 1, -5, 4};
        System.out.println("Maximum subarray sum: " + maxSubarraySum(nums));

        int[] nums2 = {2, 3, -2, 4};
        System.out.println("Maximum subarray product: " + maxSubarrayProduct(nums2));
    }

    /**
     * Kadane's Algorithm for Maximum Subarray Sum
     * Time: O(n), Space: O(1)
     */
    public static int maxSubarraySum(int[] nums) {
        int current = 0;
        int max = nums[0];

        for (int i = 0; i < nums.length; i++) {
            // Reset current sum if it becomes negative
            if (current < 0) {
                current = 0;
            }
            current = current + nums[i];
            max = Math.max(max, current);
        }

        return max;
    }

    /**
     * Maximum Product Subarray using Dynamic Programming
     * Track both max and min products (negative * negative = positive)
     * Time: O(n), Space: O(1)
     */
    public static int maxSubarrayProduct(int[] nums) {
        if (nums.length == 0) return 0;

        int max = nums[0];
        int min = nums[0];
        int result = max;

        for (int i = 1; i < nums.length; i++) {
            int curr = nums[i];

            // Store temp max before updating min
            int temp = Math.max(curr, Math.max(max * curr, min * curr));
            min = Math.min(curr, Math.min(max * curr, min * curr));
            max = temp;

            result = Math.max(result, max);
        }

        return result;
    }
}

// Maximum Subarray Sum - Kadane's Algorithm
// Example: [-2,1,-3,4,-1,2,1,-5,4]
// Output: 6 (subarray [4,-1,2,1])

// Maximum Product Subarray
// Example: [2,3,-2,4]
// Output: 6 (subarray [2,3])
